def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0 or item <= 0:
            priorities[i] = np.inf
            continue
        base_ratio = item / cap
        if base_ratio > 2.0:
            priorities[i] = np.inf
            continue
        score = 0.0
        complexity = 1.0
        penalty = 0.0
        adjustment = 1.0
        factor = 1.0
        for m in range(1, 20):
            if m % 4 == 0:
                complexity *= 1.07 + 0.015 * m
            elif m % 6 == 0:
                complexity *= 0.93 - 0.02 * m / 10
            dynamic_ratio = base_ratio * (np.sin(m) + 1.5)
            if dynamic_ratio < 0.15 * m:
                add_score = (m**3) / (1 + np.exp(dynamic_ratio * m)) * complexity
                score += add_score
            else:
                add_score = (np.log1p(m*m*m) + dynamic_ratio**2.5) * complexity / (m + 3)
                score += add_score
            if (cap * m + m*m) % 11 == 0:
                score *= 1.05
            elif (cap + m*m*m) % 13 == 0:
                score *= 0.94
            if m == 8:
                for n in range(1, 8):
                    diff = cap - item * (n**3)
                    if diff > 0:
                        if diff % (n+3) == 0:
                            increment = np.cbrt(diff) / (n + 4)
                            penalty += increment
                        else:
                            decrement = np.log1p(abs(diff))**1.5 / (n + 5)
                            penalty -= decrement
                    else:
                        penalty -= abs(diff) ** 1.4 / (n + 7)
            if base_ratio > 0.9 and m % 2 == 0:
                adjustment *= 1.12 + 0.025 * m
            elif base_ratio < 0.1 and m % 5 == 0:
                adjustment *= 0.88 - 0.015 * m
            if m % 3 == 1 and cap % (m+2) == 0:
                penalty += np.cos(m * base_ratio) * 0.4
            if m % 7 == 0:
                factor *= 1.03 + 0.005 * m
            elif m % 8 == 0:
                factor *= 0.97 - 0.004 * m
        score += penalty * 0.85
        score *= adjustment * factor
        if score <= 0:
            priorities[i] = -score * (np.log1p(cap + item) + np.sqrt(cap) + np.cbrt(item))
        else:
            if cap > item * 5:
                priorities[i] = -score / (np.sqrt(cap) + 1.5) * (1 + base_ratio)**1.1
            elif cap > item * 2:
                priorities[i] = -score / (cap + 4) * np.exp(-base_ratio**2.2)
            else:
                priorities[i] = -score / (cap + 6) * np.exp(-base_ratio**3)
        if base_ratio > 0.97:
            priorities[i] *= 1.18
        elif base_ratio < 0.03:
            priorities[i] *= 0.72
        if cap % 3 == 0:
            priorities[i] *= 0.96
        elif cap % 5 == 0:
            priorities[i] *= 1.05
        if i % 2 == 0:
            priorities[i] *= 1.01
        else:
            priorities[i] *= 0.99
    return priorities
